--
-- Table structure for table `compras_itens`
--

DROP TABLE IF EXISTS `compras_itens`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `compras_itens` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `compra_id` int(11) NOT NULL,
  `quantidade` decimal(10,2) NOT NULL DEFAULT 1.00,
  `unidade` varchar(191) NOT NULL,
  `valor_unitario` decimal(10,2) NOT NULL DEFAULT 0.00,
  `valor_total` decimal(10,2) NOT NULL DEFAULT 0.00,
  `criado_em` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `produto_id` int(11) DEFAULT NULL,
  `cor` varchar(191) DEFAULT NULL,
  `marca` varchar(191) DEFAULT NULL,
  `medida` varchar(191) DEFAULT NULL,
  `nome_produto` varchar(191) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `compras_itens_compra_id_idx` (`compra_id`),
  KEY `compras_itens_produto_id_idx` (`produto_id`),
  CONSTRAINT `compras_itens_compra_id_fkey` FOREIGN KEY (`compra_id`) REFERENCES `compras` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `compras_itens_produto_id_fkey` FOREIGN KEY (`produto_id`) REFERENCES `produtos` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=570 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

