DROP TABLE IF EXISTS `produtos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `produtos` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `fornecedor_id` int(11) NOT NULL,
  `nome_produto` varchar(191) NOT NULL,
  `cor` varchar(191) DEFAULT NULL,
  `medida` varchar(191) DEFAULT NULL,
  `quantidade` int(11) DEFAULT 0,
  `valor_unitario` decimal(10,2) DEFAULT NULL,
  `valor_total` decimal(10,2) DEFAULT NULL,
  `status` varchar(191) NOT NULL DEFAULT 'ATIVO',
  `criado_em` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `atualizado_em` datetime(3) NOT NULL,
  `marca` varchar(191) DEFAULT NULL,
  `unidade` varchar(191) DEFAULT NULL,
  `imagem_url` varchar(191) DEFAULT NULL,
  `comprimento_mm` int(11) DEFAULT NULL,
  `espessura_mm` int(11) DEFAULT NULL,
  `largura_mm` int(11) DEFAULT NULL,
  `preco_m2` decimal(10,2) DEFAULT NULL,
  `estoque_minimo` int(11) DEFAULT 0,
  `categoria` varchar(191) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `produtos_fornecedor_id_idx` (`fornecedor_id`),
  CONSTRAINT `produtos_fornecedor_id_fkey` FOREIGN KEY (`fornecedor_id`) REFERENCES `fornecedor` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=266 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

